import json

# Load metadata and extract ID ranges
with open(locals()['var_functions.query_db:5'], 'r') as f:
    metadata_2015 = json.load(f)

# Group article IDs by regions
region_to_ids = {}
for rec in metadata_2015:
    region = rec['region']
    if region not in region_to_ids:
        region_to_ids[region] = []
    region_to_ids[region].append(int(rec['article_id']))

# Calculate statistics for each region
region_stats = {}
for region, ids in region_to_ids.items():
    region_stats[region] = {
        'count': len(ids),
        'min_id': min(ids),
        'max_id': max(ids),
        'id_range': max(ids) - min(ids)
    }

print('__RESULT__:')
print(json.dumps(region_stats))

